.wrapper.rt-oe {
  --surface: var(--block-bg-color, #15151A);
  --surface-raised: #1B1B22;
  --ink: var(--color-text, #F4F4F7);
  --muted: var(--color-gray-500, #8A8A96);
  --line: var(--color-gray-200, rgba(255,255,255,.07));
  --line-soft: rgba(255,255,255,.06);
  --accent: var(--color-primary, #FFD21E);
  --accent-2: var(--color-secondary, #FF3D8B);
  container-type: inline-size;
  display: flex;
  flex-direction: column;
  gap: 12px;
  height: 100%;
  min-height: 0;
  box-sizing: border-box;
  color: var(--ink);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
}

/* ---- toolbar / header ---- */
.rt-oe .oe-bar { display: flex; flex-wrap: wrap; align-items: flex-end; gap: 12px; }
.rt-oe .oe-titles { margin-right: auto; min-width: 0; }
.rt-oe .oe-eyebrow {
  display: inline-flex; align-items: center; gap: 8px;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em; text-transform: uppercase; color: var(--muted);
}
.rt-oe .oe-eyebrow::before {
  content: ""; flex: 0 0 auto; width: 6px; height: 6px; border-radius: 50%;
  background: var(--accent);
}
.rt-oe .oe-title {
  margin: 6px 0 0;
  font: 800 22px/1.15 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.015em; color: var(--ink);
  overflow-wrap: anywhere;
}
.rt-oe .oe-tools { display: flex; align-items: center; gap: 8px; min-width: 0; }
.rt-oe .oe-search {
  box-sizing: border-box;
  font: 500 13px/1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  width: 240px; max-width: 100%; padding: 9px 12px;
  border-radius: 10px; border: 1px solid var(--line);
  background: var(--surface-raised); color: var(--ink);
  transition: border-color .15s ease, box-shadow .15s ease, background-color .15s ease;
}
.rt-oe .oe-search::placeholder { color: var(--muted); }
.rt-oe .oe-search:hover { border-color: color-mix(in srgb, var(--accent) 28%, var(--line)); }
.rt-oe .oe-search:focus-visible {
  outline: 2px solid var(--accent); outline-offset: 2px;
  border-color: color-mix(in srgb, var(--accent) 45%, var(--line));
  box-shadow: 0 0 18px -8px color-mix(in srgb, var(--accent) 55%, transparent);
}

/* ---- table shell ---- */
.rt-oe .oe-tablewrap {
  flex: 1; min-height: 0; min-width: 0; overflow: auto; overflow-x: auto;
  -webkit-overflow-scrolling: touch; overscroll-behavior: contain;
  border-radius: 14px; border: 1px solid var(--line); background: var(--surface);
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  scrollbar-width: thin;
  scrollbar-color: var(--color-gray-400, #3A3A44) transparent;
}
.rt-oe .oe-tablewrap:focus-visible { outline: 2px solid var(--accent); outline-offset: 2px; }
.rt-oe .oe-tablewrap::-webkit-scrollbar { width: 10px; height: 10px; }
.rt-oe .oe-tablewrap::-webkit-scrollbar-track { background: transparent; }
.rt-oe .oe-tablewrap::-webkit-scrollbar-thumb {
  background: var(--color-gray-400, #3A3A44); border-radius: 8px;
  border: 2px solid var(--surface);
}
.rt-oe .oe-tablewrap::-webkit-scrollbar-thumb:hover { background: var(--color-gray-500, #8A8A96); }

.rt-oe table { width: 100%; border-collapse: separate; border-spacing: 0;
  font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif); }

/* ---- sticky header ---- */
.rt-oe thead th {
  position: sticky; top: 0; z-index: 2; background: var(--surface);
  text-align: left; padding: 11px 12px; white-space: nowrap;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .06em; text-transform: uppercase; color: var(--muted);
  border-bottom: 1px solid var(--line); cursor: pointer; user-select: none;
  box-shadow: 0 8px 14px -10px rgba(0,0,0,.7);
  transition: color .15s ease, box-shadow .15s ease;
}
.rt-oe thead th.num { text-align: right; }
.rt-oe thead th:hover { color: var(--ink); }
.rt-oe thead th:active { color: var(--accent); }
.rt-oe thead th.sorted { color: var(--accent); box-shadow: inset 0 -2px 0 var(--accent), 0 8px 14px -10px rgba(0,0,0,.7); }
.rt-oe thead th:focus-visible { outline: 2px solid var(--accent); outline-offset: -2px; }
.rt-oe thead th .arrow { font-size: 10px; color: var(--accent); }

/* ---- body rows ---- */
.rt-oe tbody td {
  padding: 9px 12px; border-top: 1px solid var(--line-soft);
  color: var(--ink); white-space: nowrap;
  transition: background-color .12s ease;
}
.rt-oe tbody td.num { text-align: right; font-variant-numeric: tabular-nums; }
.rt-oe tbody tr:hover td { background: var(--surface-raised); }
.rt-oe tbody tr.is-selected td { box-shadow: inset 3px 0 0 var(--accent); }
.rt-oe tbody tr.empty td { text-align: center; color: var(--muted); padding: 26px 12px; white-space: normal; }

/* ---- status badges (calm pill, colored dot carries meaning) ---- */
.rt-oe .badge {
  display: inline-flex; align-items: center; gap: 7px;
  padding: 4px 10px 4px 9px; border-radius: 999px;
  background: rgba(255,255,255,.035); border: 1px solid var(--line);
  font: 600 12px/1 var(--font-stack-primary, 'Inter', system-ui, sans-serif); color: var(--ink);
}
.rt-oe .badge .dot { width: 7px; height: 7px; border-radius: 50%; background: var(--muted); flex: 0 0 auto; }
.rt-oe .badge.ok .dot { background: var(--color-success, #36D399); }
.rt-oe .badge.info .dot { background: var(--color-info, #34B9F3); }
.rt-oe .badge.warn .dot { background: var(--color-warning, #F6C453); }
.rt-oe .badge.bad .dot { background: var(--color-danger, #FF5A6E); }

/* ---- footer ---- */
.rt-oe .oe-foot { font: 600 11px/1.3 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  color: var(--muted); padding: 0 2px; font-variant-numeric: tabular-nums; }

/* ---- responsive (container-query driven; block sizes to its own grid cell, not the viewport) ---- */
/* filter bar wraps: title keeps its own line, search goes full-width on a narrow cell */
@container (max-width: 640px) {
  .rt-oe .oe-bar { align-items: stretch; gap: 10px; }
  .rt-oe .oe-tools { width: 100%; }
  .rt-oe .oe-search { width: 100%; }
}

@container (max-width: 420px) {
  .rt-oe .oe-title {
    font: 800 clamp(16px, 5.6cqi, 22px)/1.15 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
    letter-spacing: -.015em;
  }
  .rt-oe thead th,
  .rt-oe tbody td { padding-left: 10px; padding-right: 10px; }
}

/* ---- touch targets >=44px on coarse pointers (device capability, not cell width) ---- */
@media (pointer: coarse) {
  .rt-oe .oe-search { min-height: 44px; }
  .rt-oe thead th { padding-top: 16px; padding-bottom: 16px; }
}

@media (prefers-reduced-motion: reduce) {
  .rt-oe .oe-search,
  .rt-oe thead th,
  .rt-oe tbody td { transition: none; }
}
